<template><div><PageHeader eyebrow="DEV TOOLS" title="服务健康检查" description="通过 Gateway 验证各个业务微服务是否可访问"><el-button type="primary" @click="testAll">全部测试</el-button></PageHeader><div class="health-grid"><el-card v-for="s in services" :key="s.path" shadow="never"><div class="health-head"><strong>{{ s.name }}</strong><el-tag :type="s.status==='ok'?'success':s.status==='error'?'danger':'info'">{{ label(s.status) }}</el-tag></div><code>{{ s.path }}</code><p>{{ s.result||'尚未测试' }}</p><el-button size="small" @click="test(s)">测试</el-button></el-card></div></div></template>
<script setup>import { reactive } from 'vue';import PageHeader from '../../components/PageHeader.vue';import { healthServices,pingService } from '../../api/health';const services=reactive(healthServices.map(([name,path])=>({name,path,status:'idle',result:''})));const label=s=>({idle:'未测试',loading:'测试中',ok:'正常',error:'异常'}[s]);async function test(s){s.status='loading';try{const r=await pingService(s.path);s.result=typeof r==='string'?r:JSON.stringify(r);s.status='ok'}catch(e){s.result=e.message;s.status='error'}}async function testAll(){await Promise.all(services.map(test))}</script>
